@page "/tickets"
@using sv_daf02a1ff669450f8e00886ee5e4701d.Services
@inject ITicketService TicketService
@rendermode InteractiveServer

<PageTitle>Help Desk Tickets</PageTitle>

<div class="tickets-dashboard">
    <!-- Top Bar -->
    <div class="top-bar">
        <div class="search-box">
            <input type="text" placeholder="Search tickets..." @bind="searchQuery" @bind:event="oninput" @onkeyup="HandleSearchKeyUp" />
            <button @onclick="LoadTicketsAsync">Search</button>
        </div>
        <div class="status-tabs">
            @foreach (var tab in statusTabs)
            {
                <button class="tab @(statusFilter == tab.Value ? "active" : "")" @onclick="() => SetStatusFilter(tab.Value)">
                    @tab.Label
                </button>
            }
        </div>
        <div class="priority-filter">
            <select @bind="priorityFilter" @bind:after="LoadTicketsAsync">
                <option value="">All Priorities</option>
                <option value="Critical">Critical</option>
                <option value="High">High</option>
                <option value="Medium">Medium</option>
                <option value="Low">Low</option>
            </select>
        </div>
    </div>

    <!-- Main Content -->
    <div class="main-content">
        <!-- Left Panel -->
        <div class="left-panel">
            @if (tickets is null)
            {
                <p class="loading">Loading tickets...</p>
            }
            else if (tickets.Count == 0)
            {
                <p class="no-tickets">No tickets found.</p>
            }
            else
            {
                @foreach (var ticket in tickets)
                {
                    <div class="ticket-card @(selectedTicket?.Id == ticket.Id ? "active" : "")" @onclick="() => SelectTicket(ticket)">
                        <div class="ticket-card-header">
                            <span class="priority-dot @GetPriorityClass(ticket.Priority)"></span>
                            <span class="ticket-subject">@ticket.Subject</span>
                        </div>
                        <div class="ticket-card-meta">
                            <span class="ticket-requester">@ticket.Requester</span>
                            <span class="ticket-time">@GetRelativeTime(ticket.CreatedAt)</span>
                        </div>
                        <span class="status-badge @GetStatusBadgeClass(ticket.Status)">@ticket.Status</span>
                    </div>
                }
            }
        </div>

        <!-- Right Panel -->
        <div class="right-panel">
            @if (selectedTicket is null)
            {
                <div class="no-selection">
                    <p>Select a ticket to view details</p>
                </div>
            }
            else
            {
                <div class="detail-view">
                    <div class="detail-header">
                        <h2>@selectedTicket.Subject</h2>
                        <div class="detail-header-controls">
                            <select value="@selectedTicket.Status" @onchange="HandleStatusChange">
                                <option value="Open">Open</option>
                                <option value="In Progress">In Progress</option>
                                <option value="Resolved">Resolved</option>
                            </select>
                            <span class="priority-badge @GetPriorityClass(selectedTicket.Priority)">@selectedTicket.Priority</span>
                        </div>
                        <p class="detail-opened-by">Opened by @selectedTicket.Requester on @selectedTicket.CreatedAt.ToString("MMMM d, yyyy")</p>
                    </div>

                    <div class="detail-body">
                        <p>@selectedTicket.Description</p>
                    </div>

                    <div class="comment-section">
                        <h3>Comments</h3>
                        @if (comments is null)
                        {
                            <p class="loading">Loading comments...</p>
                        }
                        else if (comments.Count == 0)
                        {
                            <p class="no-comments">No comments yet.</p>
                        }
                        else
                        {
                            <div class="comment-list">
                                @foreach (var comment in comments)
                                {
                                    <div class="comment">
                                        <div class="comment-header">
                                            <strong>@comment.Author</strong>
                                            <span class="comment-time">@comment.PostedAt.ToString("MMM d, yyyy h:mm tt")</span>
                                        </div>
                                        <p class="comment-text">@comment.Text</p>
                                    </div>
                                }
                            </div>
                        }

                        <div class="add-comment">
                            <textarea placeholder="Add a comment..." @bind="newCommentText"></textarea>
                            <button @onclick="SubmitCommentAsync" disabled="@string.IsNullOrWhiteSpace(newCommentText)">Submit</button>
                        </div>
                    </div>
                </div>
            }
        </div>
    </div>

    <!-- Footer Bar -->
    <div class="footer-bar">
        @if (tickets is not null)
        {
            var openCount = tickets.Count(t => t.Status == "Open");
            var inProgressCount = tickets.Count(t => t.Status == "In Progress");
            var resolvedCount = tickets.Count(t => t.Status == "Resolved");
            <span>@openCount open · @inProgressCount in progress · @resolvedCount resolved</span>
        }
    </div>
</div>

