    border-radius: 4px;
    width: 220px;
}

.search-box button {
    padding: 0.4rem 0.75rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    background: #fff;
    cursor: pointer;
}

.search-box button:hover {
    background: #f0f0f0;
}

.status-tabs {
    display: flex;
    gap: 0.25rem;
}

.status-tabs .tab {
    padding: 0.4rem 0.75rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    background: #fff;
    cursor: pointer;
    font-size: 0.875rem;
}

.status-tabs .tab.active {
    background: #0d6efd;
