.tickets-dashboard {
    display: flex;
    flex-direction: column;
    height: 100vh;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
}

/* Top Bar */
.top-bar {
    display: flex;
    align-items: center;
    gap: 1rem;
    padding: 0.75rem 1rem;
    border-bottom: 1px solid #e0e0e0;
    background: #fafafa;
    flex-wrap: wrap;
}

.search-box {
    display: flex;
    gap: 0.5rem;
}

.search-box input {
    padding: 0.4rem 0.75rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    width: 220px;
}

.search-box button {
    padding: 0.4rem 0.75rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    background: #fff;
    cursor: pointer;
}

.search-box button:hover {
    background: #f0f0f0;
}

.status-tabs {
    display: flex;
    gap: 0.25rem;
}

.status-tabs .tab {
    padding: 0.4rem 0.75rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    background: #fff;
    cursor: pointer;
    font-size: 0.875rem;
}

.status-tabs .tab.active {
    background: #0d6efd;
    color: #fff;
    border-color: #0d6efd;
}

.status-tabs .tab:hover:not(.active) {
    background: #f0f0f0;
}

.priority-filter select {
    padding: 0.4rem 0.75rem;
    border: 1px solid #ccc;
    border-radius: 4px;
}

/* Main Content */
.main-content {
    display: flex;
    flex: 1;
    overflow: hidden;
}

/* Left Panel */
.left-panel {
    width: 40%;
    overflow-y: auto;
    border-right: 1px solid #e0e0e0;
    background: #f9f9f9;
}

.ticket-card {
    padding: 0.75rem 1rem;
    border-bottom: 1px solid #eee;
    cursor: pointer;
    transition: background 0.15s;
}

.ticket-card:hover {
    background: #eef2ff;
}

.ticket-card.active {
    background: #dbeafe;
    border-left: 3px solid #0d6efd;
}

.ticket-card-header {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    margin-bottom: 0.25rem;
}

.priority-dot {
    width: 10px;
    height: 10px;
    border-radius: 50%;
    flex-shrink: 0;
}

.priority-critical {
    background-color: #dc3545;
}

.priority-high {
    background-color: #fd7e14;
}

.priority-medium {
    background-color: #ffc107;
}

.priority-low {
    background-color: #6c757d;
}

.ticket-subject {
    font-weight: 500;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    flex: 1;
}

.ticket-card-meta {
    display: flex;
    justify-content: space-between;
    font-size: 0.8rem;
    color: #666;
    margin-bottom: 0.25rem;
}

.status-badge {
    font-size: 0.7rem;
    padding: 0.15rem 0.5rem;
    border-radius: 10px;
    font-weight: 500;
    display: inline-block;
}

.status-open {
    background: #dcfce7;
    color: #166534;
}

.status-in-progress {
    background: #fef3c7;
    color: #92400e;
}

.status-resolved {
    background: #e0e7ff;
    color: #3730a3;
}

/* Right Panel */
.right-panel {
    width: 60%;
    overflow-y: auto;
    padding: 1.5rem;
}

.no-selection {
    display: flex;
    align-items: center;
    justify-content: center;
    height: 100%;
    color: #999;
    font-size: 1.1rem;
}

.detail-header h2 {
    margin: 0 0 0.5rem 0;
}

.detail-header-controls {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    margin-bottom: 0.5rem;
}

.detail-header-controls select {
    padding: 0.3rem 0.5rem;
    border: 1px solid #ccc;
    border-radius: 4px;
}

.priority-badge {
    padding: 0.2rem 0.6rem;
    border-radius: 4px;
    color: #fff;
    font-size: 0.75rem;
    font-weight: 600;
}

.detail-opened-by {
    font-size: 0.85rem;
    color: #666;
    margin-bottom: 1rem;
}

.detail-body {
    margin-bottom: 1.5rem;
    line-height: 1.6;
    border-bottom: 1px solid #eee;
    padding-bottom: 1rem;
}

/* Comments */
.comment-section h3 {
    margin-bottom: 0.75rem;
}

.comment-list {
    display: flex;
    flex-direction: column;
    gap: 0.75rem;
    margin-bottom: 1rem;
}

.comment {
    background: #f8f9fa;
    border: 1px solid #eee;
    border-radius: 6px;
    padding: 0.75rem;
}

.comment-header {
    display: flex;
    justify-content: space-between;
    margin-bottom: 0.25rem;
    font-size: 0.85rem;
}

.comment-time {
    color: #888;
}

.comment-text {
    margin: 0;
    font-size: 0.9rem;
}

.add-comment {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
    margin-top: 1rem;
}

.add-comment textarea {
    padding: 0.5rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    resize: vertical;
    min-height: 80px;
    font-family: inherit;
}

.add-comment button {
    align-self: flex-end;
    padding: 0.5rem 1.25rem;
    background: #0d6efd;
    color: #fff;
    border: none;
    border-radius: 4px;
    cursor: pointer;
    font-weight: 500;
}

.add-comment button:hover:not(:disabled) {
    background: #0b5ed7;
}

.add-comment button:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

/* Footer */
.footer-bar {
    padding: 0.5rem 1rem;
    border-top: 1px solid #e0e0e0;
    background: #fafafa;
    font-size: 0.85rem;
    color: #555;
}

.loading, .no-tickets, .no-comments {
    padding: 1rem;
    color: #888;
    text-align: center;
}

