namespace sv_daf02a1ff669450f8e00886ee5e4701d.Services;

public record Ticket(int Id, string Subject, string Description, string Requester, string Priority, string Status, DateTime CreatedAt);
public record Comment(int Id, string Author, string Text, DateTime PostedAt);

public interface ITicketService
{
    Task<List<Ticket>> GetTicketsAsync(string? statusFilter, string? priorityFilter, string? searchQuery);
    Task<List<Comment>> GetCommentsAsync(int ticketId);
    Task AddCommentAsync(int ticketId, string text);
    Task UpdateStatusAsync(int ticketId, string newStatus);
}

namespace sv_daf02a1ff669450f8e00886ee5e4701d.Services;

